  </head>
  <body>
    <div class="card">
      <div class="progress-wrap">
        <div class="progress-bar" id="prog" style="width: 33%"></div>
      </div>

      <!-- Header -->
      <div class="card-header" id="hdr">
        <div class="brand">
          <div class="brand-mark">iiC</div>
          <div class="brand-text">
            <div class="name">บริษัท ไอไอซี จำกัด</div>
            <div class="sub">
              IT Infrastructure · Cybersecurity · Data Center
            </div>
          </div>
        </div>
        <h1>แจ้งความสนใจเพิ่มเติม</h1>
        <p>กรอกข้อมูลสั้น ๆ เพื่อให้ทีม Presales ติดต่อกลับอย่างตรงจุด</p>
        <div class="endpoint-badge">
          <span class="endpoint-dot"></span>POST → /webhook/other-interest-form
        </div>
      </div>

      <!-- Body -->
      <div class="card-body" id="bdy">
        <!-- Step nav -->
        <div class="step-nav">
          <div class="step-item active" id="s1">
            <span class="step-dot" id="sd1">1</span>
            <span>ข้อมูลส่วนตัว</span>
          </div>
          <div class="step-line"></div>
          <div class="step-item" id="s2">
            <span class="step-dot" id="sd2">2</span>
            <span>ความสนใจ</span>
          </div>
          <div class="step-line"></div>
          <div class="step-item" id="s3">
            <span class="step-dot" id="sd3">3</span>
            <span>รายละเอียด</span>
          </div>
        </div>

        <!-- Step 1: Personal info -->
        <div id="step1">
          <div class="grid-2">
            <div class="field">
              <label>ชื่อ-นามสกุล<span class="req">*</span></label>
              <input type="text" id="name" placeholder="เช่น สมชาย ใจดี" />
              <div class="err-msg" id="e-name">กรุณากรอกชื่อ-นามสกุล</div>
            </div>
            <div class="field">
              <label>ตำแหน่ง</label>
              <input type="text" id="position" placeholder="เช่น IT Manager" />
            </div>
          </div>
          <div class="field">
            <label>อีเมล<span class="req">*</span></label>
            <input type="email" id="email" placeholder="name@company.com" />
            <div class="err-msg" id="e-email">กรุณากรอกอีเมลให้ถูกต้อง</div>
          </div>
          <div class="grid-2">
            <div class="field">
              <label>เบอร์โทรศัพท์<span class="req">*</span></label>
              <input type="tel" id="phone" placeholder="08x-xxx-xxxx" />
              <div class="err-msg" id="e-phone">กรุณากรอกเบอร์โทรศัพท์</div>
            </div>
            <div class="field">
              <label>บริษัท / องค์กร</label>
              <input type="text" id="company" placeholder="ชื่อบริษัท" />
            </div>
          </div>
          <div class="btn-row">
            <button class="btn btn-primary" onclick="next(2)">ถัดไป →</button>
          </div>
        </div>

        <!-- Step 2: Interest -->
        <div id="step2" style="display: none">
          <div class="field">
            <label>ประเภทโซลูชันที่สนใจ<span class="req">*</span></label>
            <div class="chip-group" id="chips-sol">
              <span class="chip" onclick="tog(this)">IT Infrastructure</span>
              <span class="chip" onclick="tog(this)">Cybersecurity</span>
              <span class="chip" onclick="tog(this)">Data Center</span>
              <span class="chip" onclick="tog(this)">Cloud Services</span>
              <span class="chip" onclick="tog(this)"
                >Network &amp; Connectivity</span
              >
              <span class="chip" onclick="tog(this)"
                >Backup &amp; Recovery</span
              >
              <span class="chip" onclick="tog(this)">Endpoint Security</span>
              <span class="chip" onclick="tog(this)">อื่น ๆ</span>
            </div>
            <div class="err-msg" id="e-sol">กรุณาเลือกอย่างน้อย 1 รายการ</div>
          </div>
          <div class="grid-2" style="margin-top: 16px">
            <div class="field">
              <label>ระยะเวลาการวางแผน</label>
              <select id="timeline">
                <option value="">-- เลือกระยะเวลา --</option>
                <option>ภายใน 1 เดือน</option>
                <option>1–3 เดือน</option>
                <option>3–6 เดือน</option>
                <option>6–12 เดือน</option>
                <option>มากกว่า 1 ปี</option>
              </select>
            </div>
            <div class="field">
              <label>งบประมาณโดยประมาณ</label>
              <select id="budget">
                <option value="">-- เลือกช่วงงบ --</option>
                <option>น้อยกว่า 500,000 บาท</option>
                <option>500,000 – 2,000,000 บาท</option>
                <option>2,000,000 – 5,000,000 บาท</option>
                <option>มากกว่า 5,000,000 บาท</option>
                <option>ยังไม่ได้กำหนด</option>
              </select>
            </div>
          </div>
          <div class="btn-row">
            <button class="btn btn-ghost" onclick="next(1)">← ย้อนกลับ</button>
            <button class="btn btn-primary" onclick="next(3)">ถัดไป →</button>
          </div>
        </div>

        <!-- Step 3: Detail -->
        <div id="step3" style="display: none">
          <div class="field">
            <label>อธิบายความต้องการโดยย่อ<span class="req">*</span></label>
            <textarea
              id="detail"
              maxlength="500"
              placeholder="เช่น ต้องการอัปเกรด Firewall สำหรับ 200 users รองรับ remote work…"
              oninput="cc()"
            ></textarea>
            <div class="char-count"><span id="cc">0</span>/500</div>
            <div class="err-msg" id="e-detail">
              กรุณาอธิบายความต้องการสั้น ๆ
            </div>
          </div>
          <div class="field">
            <label>ช่องทางที่สะดวกให้ติดต่อกลับ</label>
            <div class="chip-group" id="chips-con">
              <span class="chip" onclick="tog(this)">โทรศัพท์</span>
              <span class="chip on" onclick="tog(this)">Line</span>
              <span class="chip" onclick="tog(this)">อีเมล</span>
              <span class="chip" onclick="tog(this)">Online Meeting</span>
            </div>
          </div>
          <div class="field">
            <label>เวลาที่สะดวก</label>
            <select id="best-time">
              <option value="">-- เลือกช่วงเวลา --</option>
              <option>ช่วงเช้า (09:00–12:00)</option>
              <option>ช่วงบ่าย (13:00–17:00)</option>
              <option>ช่วงเย็น (17:00–19:00)</option>
              <option>ยืดหยุ่นได้</option>
            </select>
          </div>
          <div class="divider"></div>
          <div class="btn-row">
            <button class="btn btn-ghost" onclick="next(2)">← ย้อนกลับ</button>
            <button class="btn btn-primary" id="submit-btn" onclick="submit()">
              ส่งข้อมูล →
            </button>
          </div>
        </div>
      </div>

      <!-- Success screen -->
      <div class="success" id="success">
        <div class="success-icon">✓</div>
        <h2>ขอบคุณสำหรับข้อมูลครับ!</h2>
        <p>ทีม Presales จะติดต่อกลับภายใน <strong>1–2 วันทำการ</strong></p>
        <div class="summary" id="summary"></div>
        <p class="footer-note">
          บริษัท ไอไอซี จำกัด · หากมีข้อสงสัยติดต่อ sales@iic.co.th
        </p>
      </div>
    </div>

    <script>
      var cur = 1;

      function next(n) {
        if (n > cur && !validate(cur)) return;
        document.getElementById("step" + cur).style.display = "none";
        document.getElementById("step" + n).style.display = "block";
        cur = n;
        updateNav();
        window.scrollTo({ top: 0, behavior: "smooth" });
      }

      function updateNav() {
        var pct = { 1: 33, 2: 66, 3: 100 };
        document.getElementById("prog").style.width = pct[cur] + "%";
        [1, 2, 3].forEach(function (i) {
          var s = document.getElementById("s" + i);
          var d = document.getElementById("sd" + i);
          s.className =
            "step-item" + (i < cur ? " done" : i === cur ? " active" : "");
          d.textContent = i < cur ? "✓" : i;
        });
      }

      function validate(n) {
        var ok = true;
        if (n === 1) {
          var nm = v("name"),
            em = v("email"),
            ph = v("phone");
          var re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
          err("name", !nm);
          err("email", !re.test(em));
          err("phone", !ph);
          if (!nm || !re.test(em) || !ph) ok = false;
        }
        if (n === 2) {
          var none = sel("#chips-sol .chip.on").length === 0;
          document.getElementById("e-sol").classList.toggle("show", none);
          if (none) ok = false;
        }
        if (n === 3) {
          var dt = v("detail");
          err("detail", !dt);
          if (!dt) ok = false;
        }
        return ok;
      }

      function v(id) {
        return document.getElementById(id).value.trim();
      }
      function err(id, isErr) {
        var el = document.getElementById(id);
        var msg = document.getElementById("e-" + id);
        if (el) el.classList.toggle("err", isErr);
        if (msg) msg.classList.toggle("show", isErr);
      }
      function tog(el) {
        el.classList.toggle("on");
      }
      function sel(q) {
        return Array.from(document.querySelectorAll(q));
      }
      function chips(id) {
        return sel("#" + id + " .chip.on")
          .map(function (c) {
            return c.textContent.trim();
          })
          .join(", ");
      }
      function cc() {
        document.getElementById("cc").textContent =
          document.getElementById("detail").value.length;
      }

      function submit() {
        if (!validate(3)) return;
        var btn = document.getElementById("submit-btn");
        btn.disabled = true;
        btn.textContent = "กำลังส่ง...";

        var payload = {
          name: v("name"),
          position: v("position"),
          email: v("email"),
          phone: v("phone"),
          company: v("company"),
          interest: chips("chips-sol"),
          timeline: document.getElementById("timeline").value,
          budget: document.getElementById("budget").value,
          detail: v("detail"),
          contactPref: chips("chips-con"),
          bestTime: document.getElementById("best-time").value,
        };

        /* POST to Webhook - Other Interest Form node */
        fetch(
          "http://localhost:5678/webhook-test/other-interest-form",
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
          },
        )
          .catch(function () {})
          .finally(function () {
            showSuccess(payload);
          });
      }

      function showSuccess(p) {
        document.getElementById("prog").style.width = "100%";
        document.getElementById("prog").style.background = "#3B6D11";
        document.getElementById("hdr").style.display = "none";
        document.getElementById("bdy").style.display = "none";

        var rows = [
          ["ชื่อ", p.name + (p.position ? " – " + p.position : "")],
          ["อีเมล", p.email],
          ["เบอร์โทร", p.phone],
          ["บริษัท", p.company || "–"],
          ["ความสนใจ", p.interest],
          ["งบประมาณ", p.budget || "–"],
          ["ระยะเวลา", p.timeline || "–"],
          ["ติดต่อผ่าน", p.contactPref || "–"],
        ];

        document.getElementById("summary").innerHTML = rows
          .map(function (r) {
            return (
              '<div class="s-row"><span class="s-key">' +
              r[0] +
              '</span><span class="s-val">' +
              r[1] +
              "</span></div>"
            );
          })
          .join("");

